*/

'use strict';

// MODULES //

var nanstdevwd = require( './lib/node_modules/@stdlib/stats/base/nanstdevwd' );
var toAccessorArray = require( './lib/node_modules/@stdlib/array/base/to-accessor-array' );
var arraylike2object = require( './lib/node_modules/@stdlib/array/base/arraylike2-object' );


// MAIN //

console.log( 'Testing nanstdevwd accessor protocol support...' );

// Test 1: Regular array (should work as before)
var x1 = [ 1.0, -2.0, NaN, 2.0 ];
var v1 = nanstdevwd( x1.length, 1, x1, 1 );
console.log( 'Regular array result:', v1 );

// Test 2: Accessor array
var x2 = toAccessorArray( [ 1.0, -2.0, NaN, 2.0 ] );
var v2 = nanstdevwd.ndarray( x2.length, 1, x2, 1, 0 );
console.log( 'Accessor array result:', v2 );

// Test 3: Accessor array with ndarray interface
var x3 = toAccessorArray( [ 1.0, -2.0, NaN, 2.0 ] );
var x3obj = arraylike2object( x3 );
var v3 = nanstdevwd.ndarray( x3.length, 1, x3obj, 1, 0 );
console.log( 'Accessor object result:', v3 );

// Test 4: Empty array
var x4 = [];
var v4 = nanstdevwd( x4.length, 1, x4, 1 );
console.log( 'Empty array result:', v4 );

// Test 5: All NaN values
var x5 = [ NaN, NaN, NaN, NaN ];
var v5 = nanstdevwd( x5.length, 1, x5, 1 );
console.log( 'All NaN result:', v5 );

console.log( 'All tests completed.' );

