/**
* Test script for nanstdevwd accessor protocol support
*/

'use strict';

// MODULES //

var nanstdevwd = require( './lib/node_modules/@stdlib/stats/base/nanstdevwd' );
var nanvariancewd = require( './lib/node_modules/@stdlib/stats/base/nanvariancewd' );
var arraylike2object = require( './lib/node_modules/@stdlib/array/base/arraylike2object' );


// MAIN //

console.log( 'Testing nanstdevwd accessor protocol support...' );

// Test 1: Regular array (should work as before)
var x1 = [ 1.0, -2.0, NaN, 2.0 ];
var v1 = nanstdevwd( x1.length, 1, x1, 1 );
console.log( 'Regular array result:', v1 );

// Test 2: Regular array with ndarray
var v1a = nanstdevwd.ndarray( x1.length, 1, x1, 1, 0 );
console.log( 'Regular array ndarray result:', v1a );

// Test 3: Test accessor protocol awareness
var x2 = [ 1.0, -2.0, NaN, 2.0 ];
var x2obj = arraylike2object( x2 );
console.log( 'Accessor object properties:', {
    accessorProtocol: x2obj.accessorProtocol,
    dataType: typeof x2obj.data[0],
    hasAccessors: !!x2obj.accessors
} );

// Test that ndarray detects regular array vs accessor array
try {
    var v2 = nanstdevwd.ndarray( x2.length, 1, x2obj, 1, 0 );
    console.log( 'Accessor object result:', v2 );
} catch (error) {
    console.log( 'Accessor object error:', error.message );
}

// Test 4: Verify variance calculation is working correctly
var x3 = [ 1.0, -2.0, NaN, 2.0 ];
var v3var = nanvariancewd.ndarray( x3.length, 1, x3, 1, 0 );
var v3std = nanstdevwd.ndarray( x3.length, 1, x3, 1, 0 );
console.log( 'Variance:', v3var, 'Standard deviation:', v3std, 'Square root check:', Math.sqrt(v3var) );

// Test 4: Empty array
var x3 = [];
var v3 = nanstdevwd( x3.length, 1, x3, 1 );
console.log( 'Empty array result:', v3 );

// Test 5: All NaN values
var x4 = [ NaN, NaN, NaN, NaN ];
var v4 = nanstdevwd( x4.length, 1, x4, 1 );
console.log( 'All NaN result:', v4 );

console.log( 'All tests completed.' );

