/**
* Test script for nanstdevwd with true accessor arrays
*/

'use strict';

// MODULES //

var nanstdevwd = require( './lib/node_modules/@stdlib/stats/base/nanstdevwd' );
var toAccessorArray = require( './lib/node_modules/@stdlib/array/base/to-accessor-array' );


// MAIN //

console.log( 'Testing nanstdevwd with true accessor arrays...' );

// Create true accessor arrays using toAccessorArray
var x1 = toAccessorArray( [ 1.0, -2.0, NaN, 2.0 ] );
console.log( 'Accessor array type:', typeof x1 );
console.log( 'Accessor array properties:', Object.keys(x1) );

// Test if main function handles accessor arrays
try {
    var v1 = nanstdevwd( x1.length, 1, x1, 1 );
    console.log( 'Main function with accessor array:', v1 );
} catch (error) {
    console.log( 'Main function error:', error.message );
}

// Test with ndarray interface
try {
    var v2 = nanstdevwd.ndarray( x1.length, 1, x1, 1, 0 );
    console.log( 'ndarray function with accessor array:', v2 );
} catch (error) {
    console.log( 'ndarray function error:', error.message );
}

// Test with arraylike2object wrapper on accessor array
var arraylike2object = require( './lib/node_modules/@stdlib/array/base/arraylike2object' );
var x2obj = arraylike2object( x1 );
console.log( 'Accessor object from accessor array:', {
    accessorProtocol: x2obj.accessorProtocol,
    dataType: typeof x2obj.data
} );

try {
    var v3 = nanstdevwd.ndarray( x1.length, 1, x2obj, 1, 0 );
    console.log( 'ndarray with accessor object from accessor array:', v3 );
} catch (error) {
    console.log( 'ndarray with accessor object error:', error.message );
}

console.log( 'Testing completed.' );

