/**
* Exhaustive test script for nanstdevwd accessor protocol support
*/

'use strict';

// MODULES //

var nanstdevwd = require( './lib/node_modules/@stdlib/stats/base/nanstdevwd' );
var nanvariancewd = require( './lib/node_modules/@stdlib/stats/base/nanvariancewd' );
var toAccessorArray = require( './lib/node_modules/@stdlib/array/base/to-accessor-array' );


// MAIN //

console.log( '=== Comprehensive nanstdevwd accessor protocol tests ===' );

console.log( '\n1. Testing regular arrays (baseline):' );
var x = [ 1.0, -2.0, NaN, 2.0 ];
var vMain = nanstdevwd( x.length, 1, x, 1 );
var vNdArray = nanstdevwd.ndarray( x.length, 1, x, 1, 0 );
console.log( '   Main function result:', vMain );
console.log( '   Ndarray function result:', vNdArray );

console.log( '\n2. Testing accessor arrays with main function:' );
var xAcc = toAccessorArray( [ 1.0, -2.0, NaN, 2.0 ] );
try {
    var vAccMain = nanstdevwd( xAcc.length, 1, xAcc, 1 );
    console.log( '   Success:', vAccMain );
} catch (error) {
    console.log( '   Error (expected):', error.message );
}

console.log( '\n3. Testing accessor arrays with ndarray function:' );
try {
    var vAccNd = nanstdevwd.ndarray( xAcc.length, 1, xAcc, 1, 0 );
    console.log( '   Success:', vAccNd );
} catch (error) {
    console.log( '   Error (should not happen):', error.message );
}

console.log( '\n4. Verifying nanvariancewd handles accessor arrays:' );
var vVarAcc = nanvariancewd.ndarray( xAcc.length, 1, xAcc, 1, 0 );
console.log( '   Variance result:', vVarAcc );
console.log( '   Square root of variance:', Math.sqrt(vVarAcc) );

console.log( '\n5. Checking consistency:' );
if (vVarAcc !== null && !isNaN(vVarAcc)) {
    var expectedStd = Math.sqrt(vVarAcc);
    console.log( '   Expected standard deviation:', expectedStd );
    console.log( '   Actual from regular array:', vMain );
    console.log( '   Match:', Math.abs(expectedStd - vMain) < 1e-10 ? 'YES' : 'NO' );
}

console.log( '\n6. Testing edge cases:' );

// Empty array
var empty = toAccessorArray( [] );
var emptyResult = nanstdevwd.ndarray( empty.length, 1, empty, 1, 0 );
console.log( '   Empty accessor array:', emptyResult );

// All NaN
var allNaN = toAccessorArray( [ NaN, NaN, NaN, NaN ] );
var allNaNResult = nanstdevwd.ndarray( allNaN.length, 1, allNaN, 1, 0 );
console.log( '   All NaN accessor array:', allNaNResult );

// Single value
var single = toAccessorArray( [ 5.0 ] );
var singleResult = nanstdevwd.ndarray( single.length, 1, single, 1, 0 );
console.log( '   Single value accessor array:', singleResult );

console.log( '\n=== Tests completed ===' );

